"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[357],{6920:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"CuttingPart","desc":"The virtual/physical hitbox that the destruction will use.\\n\\nIf this is not provided, [CFrame](#CFrame), [Size](#Size), and [Shape](#Shape), will be used. *You must provide one or the other.*\\n\\nIf this is a Model, a destruction will be queued for every Part descendant of that Model","lua_type":"(ImaginaryPart|Part|Model)?","source":{"line":680,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"CFrame","desc":"","lua_type":"CFrame?","source":{"line":686,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"Size","desc":"","lua_type":"Vector3?","source":{"line":692,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"Shape","desc":"","lua_type":"PartType?","source":{"line":698,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"FilterTagged","desc":"Only instances with the given tag(s) are considered for voxel destruction.\\n\\nIf this is not passed, every BasePart without the `\\"Indestructible\\"` tag is considered.","lua_type":"(string | {string})?","source":{"line":708,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"CleanupDelay","desc":"The amount of time in seconds before this destruction is cleaned up.\\n\\n:::note\\nSet this to 0 to disable cleanups per-destruction\\n:::\\n\\n:::note\\nNew destructions can reset the cleanup timer of existing dirty groups, *only if the new reset time would extend the time until cleanup.*\\n\\n#### Example\\n\\nYou destroy with a `CleanupDelay` of 10, wait 4 seconds, and then with a `CleanupDelay` of 2 in the same spot. You will have to wait 6 seconds for it to come back because 6 is greater than 2.\\n\\nIf you instead waited 9 seconds, the time until cleanup would get extended to 2 seconds because 1 is less than 2.\\n:::","lua_type":"number?","source":{"line":730,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"GridSize","desc":"What GridSize this hitbox will divide parts down to.\\n\\nThis can cause issues with greedy meshing if you destroy a part using multiple grid sizes.\\n\\nYou should instead give parts a GridSize number attribute so each Part only has one GridSize.","lua_type":"number?","deprecated":{"version":"Release 7","desc":null},"source":{"line":743,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"SkipEncapsulatedVoxels","desc":"*This makes larger destructions an entire **order of magnitude** faster.*\\n\\nWhether or not to intelligently skip voxels fully contained by the hitbox.\\n\\nIf this is false, these fully contained parts are Voxelized entirely using math.\\n\\nOtherwise, they are directly deleted.\\n\\n:::note\\nIf you use this parameter you will only recieve \\"edge\\" voxels.\\n:::","lua_type":"boolean?","source":{"line":761,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"SkipFloors","desc":"","lua_type":"boolean?","source":{"line":767,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"SkipWalls","desc":"","lua_type":"boolean?","source":{"line":773,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"OnVoxelDestruct","desc":"The name of the OnVoxelDestruct effect you want to use for this destruction.\\n\\nYou can register these effects either with [Shatterbox.RegisterOnVoxelDestruct] or by making an entry in the desired `Shatterbox/effects` module.\\n\\nClient side effects should be registered on the client side, while server side effects should be registered on the server side. Client side effects only work with Client-Server enabled.\\n\\n*You should register any given effect only once in a static context, which you are then free to use anywhere else - even in other scripts.*\\n\\n```lua\\nShatterbox.RegisterOnVoxelDestruct(\\"SomeName\\", function(voxel, info)\\n\\n\\tvoxel.Anchored = false\\n\\n\\treturn\\nend)\\n\\n-- later or in another script\\nhb.OnVoxelDestruct = \\"SomeName\\"\\n```","lua_type":"string?","source":{"line":799,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"OnDestructCompleted","desc":"A callback that runs when the destruction is finished processing \\n\\n:::warning\\nThis only works with `Shatterbox.Destroy` or `hitbox:Destroy()`.\\n\\nFor ImaginaryVoxels, you can use the array of imaginary voxels to obtain the same information.\\n:::","lua_type":"OnDestructCompleted?","source":{"line":812,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"UserData","desc":"A table that is passed to the OnVoxelDestruct effect as `info.UserData`.\\n\\nYou can put variables in this table that are to be used in your effect.","lua_type":"{any}?","source":{"line":822,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"WaitForClientTimeout","desc":"If set, how many seconds the server will wait at max for each client to recieve their static map parts.\\n\\nThis only works with Client-Server enabled.\\n\\nUse this if you see the ground flashing due to the size of your destruction.\\n\\n:::danger\\nIf you use it, be sure to keep this set to a low value like 0.1 or 0.2, as exploiters/laggy players can force every destruction to take this maximum amount of time.\\n:::","lua_type":"number?","source":{"line":837,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"ExcludePlayersReplication","desc":"A player or a list of players that will not recieve the destruction.\\n\\nThis only works with Client-Server enabled.\\n\\nUse this on the server side if you have a client-initiated destruction, so the originating player doesn\'t recieve the same destruction they started.\\n\\nServer:\\n```lua\\nSomeEvent.OnServerEvent:Connect(function(plr, destructionCFrame)\\n\\t-- make sure you add sanity checks so you don\'t get hacked.\\n\\n\\thitbox.CFrame = destructionCFrame\\n\\n\\t-- do not replicate the destruction back to \\"plr\\"\\n\\thitbox.ExcludePlayersReplication = plr\\n\\n\\t-- make sure the server side hitbox and the client side hitbox are identical when you do this. Otherwise the destructon won\'t be synchronized.\\n\\thitbox:Destroy()\\nend)\\n```\\n\\nClient:\\n```lua\\nhitbox:Destroy()\\nSomeEvent:FireServer(hitbox.CFrame)\\n```","lua_type":"(Player | {Player})?","realm":["Server"],"source":{"line":871,"path":"src/shared/Shatterbox/Main.luau"}}],"types":[],"name":"DestructionParameters","desc":"A table that specifies information needed for destruction to happen, as well as all of the optional per-destruction parameters.\\n\\n:::warning\\nIf you do not supply `params.CuttingPart` then you must assign `params.CFrame`, `params.Size`, and `params.Shape` (and vice-versa).\\n:::","source":{"line":667,"path":"src/shared/Shatterbox/Main.luau"}}')}}]);